def calculate_vc(density, bulk_modulus):
    return (bulk_modulus / density) ** 0.5

def calculate_vs(density, shear_modulus):
    return (shear_modulus / density) ** 0.5

def calculate_e(shear_modulus, poisson_ratio):
    return shear_modulus * (1 + poisson_ratio) * (1 - 2 * poisson_ratio)

def calculate_shear_modulus(bulk_modulus, poisson_ratio):
    return (3 * bulk_modulus * (1 - 2 * poisson_ratio)) / (2 * (1 + poisson_ratio))

def calculate_bulk_modulus(density, vc):
    return density * vc ** 2

def calculate_poissons_ratio(vs, vc):
    return (vc ** 2 - 2 * vs ** 2) / (2 * (vc ** 2 - vs ** 2))

def calculate_p_wave_modulus(density, vc):
    return density * vc ** 2

def calculate_lambda(shear_modulus, bulk_modulus):
    return (2 * shear_modulus + bulk_modulus)

def solve(density, bulk_modulus, shear_modulus, poisson_ratio):
    vc = calculate_vc(density, bulk_modulus)
    vs = calculate_vs(density, shear_modulus)
    e = calculate_e(shear_modulus, poisson_ratio)
    shear_modulus = calculate_shear_modulus(bulk_modulus, poisson_ratio)
    bulk_modulus = calculate_bulk_modulus(density, vc)
    poisson_ratio = calculate_poissons_ratio(vs, vc)
    p_wave_modulus = calculate_p_wave_modulus(density, vc)
    lambda_value = calculate_lambda(shear_modulus, bulk_modulus)

    return {
        'Vc': vc,
        'Vs': vs,
        'E': e,
        'Shear Modulus': shear_modulus,
        'Bulk Modulus': bulk_modulus,
        'Poisson Ratio': poisson_ratio,
        'P-wave Modulus': p_wave_modulus,
        'Lambda': lambda_value
    }
